class Solution {
    public int magicalString(int n) {
        if (n <= 0) return 0;
        if (n <= 3) return 1;
        int[] s = new int[n + 1];
        s[0] = 1;
        s[1] = 2;
        s[2] = 2;
        int idx = 2, val = 1, cnt = 1, res = 1;
        while (idx < n) {
            for (int i = 0; i < s[idx - 1]; i++) {
                if (idx < n) {
                    s[idx++] = val;
                    if (val == 1) res++;
                }
            }
            val = 3 - val;
            cnt++;
        }
        return res;
    }
}
